#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_fp16 : enable

#ifdef ENABLE_HP
typedef short cl_half2[2];
#endif

#ifndef class_T
#define class_T float
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 1
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifndef BLOCK_STRIDED
#define BLOCK_STRIDED 0
#endif

__attribute__((noinline))
class_T bench_block(class_T* data, class_T f) {
  class_T sum = 0;

#ifdef BASELINE_IMPL
  class_T t = data[0];
  for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
    t = t * t + f;
  }
  sum += t;
#else
  class_T f_arr[8];
  class_T t_arr[8];

  f_arr[0] = data[0];
  f_arr[1] = data[1];
  f_arr[2] = data[2];
  f_arr[3] = data[3];
  f_arr[4] = data[4];
  f_arr[5] = data[5];
  f_arr[6] = data[6];
  f_arr[7] = data[7];

  t_arr[0] = data[0];
  t_arr[1] = data[0];
  t_arr[2] = data[0];
  t_arr[3] = data[0];
  t_arr[4] = data[0];
  t_arr[5] = data[0];
  t_arr[6] = data[0];
  t_arr[7] = data[0];

  size_t iter_count = COMPUTE_ITERATIONS / 8;
  for (size_t j = 0; j < iter_count; j++) {
    t_arr[0] = t_arr[0] * t_arr[0] + f_arr[0];
    t_arr[1] = t_arr[1] * t_arr[1] + f_arr[1];
    t_arr[2] = t_arr[2] * t_arr[2] + f_arr[2];
    t_arr[3] = t_arr[3] * t_arr[3] + f_arr[3];
    t_arr[4] = t_arr[4] * t_arr[4] + f_arr[4];
    t_arr[5] = t_arr[5] * t_arr[5] + f_arr[5];
    t_arr[6] = t_arr[6] * t_arr[6] + f_arr[6];
    t_arr[7] = t_arr[7] * t_arr[7] + f_arr[7];
  }

  int rem = COMPUTE_ITERATIONS % 8;
  if (rem > 0) t_arr[0] = t_arr[0] * t_arr[0] + f_arr[0];
  if (rem > 1) t_arr[1] = t_arr[1] * t_arr[1] + f_arr[1];
  if (rem > 2) t_arr[2] = t_arr[2] * t_arr[2] + f_arr[2];
  if (rem > 3) t_arr[3] = t_arr[3] * t_arr[3] + f_arr[3];
  if (rem > 4) t_arr[4] = t_arr[4] * t_arr[4] + f_arr[4];
  if (rem > 5) t_arr[5] = t_arr[5] * t_arr[5] + f_arr[5];
  if (rem > 6) t_arr[6] = t_arr[6] * t_arr[6] + f_arr[6];

  sum += t_arr[0] + t_arr[1] + t_arr[2] + t_arr[3] + t_arr[4] + t_arr[5] + t_arr[6] + t_arr[7];
#endif
  return sum;
}

__kernel void benchmark_func(class_T seed, __global class_T* src) {
  size_t global_id = get_global_id(0);
  size_t local_id = get_local_id(0);
  size_t group_id = get_group_id(0);

  size_t stride;
  if (BLOCK_STRIDED) {
    stride = blockdim * ELEMENTS_PER_THREAD * FUSION_DEGREE;
  } else {
    stride = get_global_size(0) * ELEMENTS_PER_THREAD * FUSION_DEGREE;
  }

  size_t base_idx = (group_id * blockdim + local_id) * ELEMENTS_PER_THREAD * FUSION_DEGREE;

  class_T local_sum = 0;

  for (size_t fusion = 0; fusion < FUSION_DEGREE; fusion++) {
    size_t offset = base_idx + fusion * ELEMENTS_PER_THREAD * blockdim;

    for (size_t i = 0; i < ELEMENTS_PER_THREAD; i++) {
      size_t idx = offset + i * blockdim;
      if (idx < get_global_size(0) * ELEMENTS_PER_THREAD * FUSION_DEGREE * blockdim / blockdim) { 
        class_T f = src[idx];
        class_T t = f;

        #ifdef BASELINE_IMPL
        for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
          t = t * t + seed;
        }
        local_sum += t;
        #else
        class_T f_arr[8];
        class_T t_arr[8];

        f_arr[0] = src[idx];
        f_arr[1] = src[idx + 1];
        f_arr[2] = src[idx + 2];
        f_arr[3] = src[idx + 3];
        f_arr[4] = src[idx + 4];
        f_arr[5] = src[idx + 5];
        f_arr[6] = src[idx + 6];
        f_arr[7] = src[idx + 7];

        t_arr[0] = f_arr[0];
        t_arr[1] = f_arr[1];
        t_arr[2] = f_arr[2];
        t_arr[3] = f_arr[3];
        t_arr[4] = f_arr[4];
        t_arr[5] = f_arr[5];
        t_arr[6] = f_arr[6];
        t_arr[7] = f_arr[7];

        size_t iter_count = COMPUTE_ITERATIONS / 8;
        for (size_t j = 0; j < iter_count; j++) {
          t_arr[0] = t_arr[0] * t_arr[0] + seed;
          t_arr[1] = t_arr[1] * t_arr[1] + seed;
          t_arr[2] = t_arr[2] * t_arr[2] + seed;
          t_arr[3] = t_arr[3] * t_arr[3] + seed;
          t_arr[4] = t_arr[4] * t_arr[4] + seed;
          t_arr[5] = t_arr[5] * t_arr[5] + seed;
          t_arr[6] = t_arr[6] * t_arr[6] + seed;
          t_arr[7] = t_arr[7] * t_arr[7] + seed;
        }

        int rem = COMPUTE_ITERATIONS % 8;
        if (rem > 0) t_arr[0] = t_arr[0] * t_arr[0] + seed;
        if (rem > 1) t_arr[1] = t_arr[1] * t_arr[1] + seed;
        if (rem > 2) t_arr[2] = t_arr[2] * t_arr[2] + seed;
        if (rem > 3) t_arr[3] = t_arr[3] * t_arr[3] + seed;
        if (rem > 4) t_arr[4] = t_arr[4] * t_arr[4] + seed;
        if (rem > 5) t_arr[5] = t_arr[5] * t_arr[5] + seed;
        if (rem > 6) t_arr[6] = t_arr[6] * t_arr[6] + seed;

        local_sum += t_arr[0] + t_arr[1] + t_arr[2] + t_arr[3] + t_arr[4] + t_arr[5] + t_arr[6] + t_arr[7];
        #endif
      }
    }
  }

  src[global_id] = local_sum;
}
